"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[179],{6812:e=>{e.exports=JSON.parse('{"functions":[],"properties":[{"name":"ResourceNodeMultiplier","desc":"A [State] object holding a number that represents an additional multiplier\\napplied to resource node yields. Defaults to `0` (no bonus).\\n\\nSet this inside an event Executor to grant bonus resources during the event,\\nand reset it to `0` in the Trove cleanup.","lua_type":"State","since":"0.1.0","source":{"line":41,"path":"packages/admin-abuse/src/EventMultipliers.luau"}}],"types":[],"name":"EventMultipliers","desc":"Holds observable [State] objects that represent gameplay multipliers tied to admin\\nevents. Event Executors can set these values, and other game systems can observe\\nthem to apply bonuses while an event is active.\\n\\nAccessed via [AdminAbuse].EventMultipliers.\\n\\n```lua\\n-- Inside an event Executor:\\nlocal AdminAbuse = require(path.to.AdminAbuse)\\nAdminAbuse.EventMultipliers.ResourceNodeMultiplier:Set(2)\\n\\n-- In a resource node system:\\nlocal multiplier = AdminAbuse.EventMultipliers.ResourceNodeMultiplier:Get()\\nlocal yield = baseYield + (baseYield * multiplier)\\n```","realm":["Server"],"since":"0.1.0","source":{"line":24,"path":"packages/admin-abuse/src/EventMultipliers.luau"}}')}}]);